 99→    private void autoSelectNewestFiles() {
100→        // 自动选择Download/Weixin目录中最新的一对文件（音频+文档）
101→        new Thread(() -> {
102→            try {
103→                File downloadDir = new File(Environment.getExternalStorageDirectory(), "Download");
104→                File weixinDir = new File(downloadDir, "Weixin");
105→                File targetDir = weixinDir.exists() ? weixinDir : downloadDir;
106→
107→                File[] files = targetDir.listFiles();
108→                if (files == null || files.length == 0) return;
109→
110→                // 按修改时间排序，最新的在前
111→                java.util.Arrays.sort(files, (a, b) -> Long.compare(b.lastModified(), a.lastModified()));
112→
113→                File newestAudio = null;
114→                File newestDoc = null;
115→
116→                // 找最新的音频和文档
117→                for (File f : files) {
118→                    String name = f.getName().toLowerCase();
119→                    if (newestAudio == null && isAudioFile(name)) {
120→                        newestAudio = f;
121→                    } else if (newestDoc == null && isDocFile(name)) {
122→                        newestDoc = f;
123→                    }
124→                    if (newestAudio != null && newestDoc != null) break;
125→                }
126→
127→                // 自动填充
128→                if (newestAudio != null) {
129→                    String path = newestAudio.getAbsolutePath();
130→                    audioPath = path;
131→                    final String name = newestAudio.getName();
132→                    runOnUiThread(() -> tvAudioName.setText(name));
133→                    Log.i(TAG, "自动选择音频: " + name);
134→                }
135→                if (newestDoc != null) {
136→                    String path = newestDoc.getAbsolutePath();
137→                    docPath = path;
138→                    final String name = newestDoc.getName();
139→                    runOnUiThread(() -> tvDocName.setText(name));
140→                    Log.i(TAG, "自动选择文档: " + name);
141→                }
142→            } catch (Exception e) {
143→                Log.e(TAG, "自动选择文件失败", e);
144→            }
145→        }).start();
146→    }
