148→    private boolean isAudioFile(String name) {
149→        return name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
150→               name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk") ||
151→               name.endsWith(".ogg") || name.endsWith(".opus") || name.endsWith(".aac");
152→    }
