327→    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
328→    private float[] decodeAudio(String filepath) throws Exception {
329→        MediaExtractor extractor = new MediaExtractor();
330→        extractor.setDataSource(filepath);
331→
332→        // 查找音频轨道
333→        int trackIndex = -1;
334→        MediaFormat format = null;
335→        for (int i = 0; i < extractor.getTrackCount(); i++) {
336→            MediaFormat f = extractor.getTrackFormat(i);
337→            String mime = f.getString(MediaFormat.KEY_MIME);
338→            if (mime != null && mime.startsWith("audio/")) {
339→                trackIndex = i;
340→                format = f;
341→                break;
342→            }
343→        }
344→        if (trackIndex < 0) {
345→            throw new Exception("未找到音频轨道，文件可能不是音频格式");
346→        }
347→
348→        extractor.selectTrack(trackIndex);
349→        String mime = format.getString(MediaFormat.KEY_MIME);
350→        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
351→        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
352→        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");
353→
354→        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();
355→
356→        if ("audio/raw".equals(mime)) {
357→            // PCM WAV: 直接从extractor读取，不需要codec解码
358→            ByteBuffer buf = ByteBuffer.allocate(65536);
359→            while (extractor.readSampleData(buf, 0) >= 0) {
360→                int pos = buf.position();
361→                byte[] chunk = new byte[pos];
362→                buf.flip();
363→                buf.get(chunk);
364→                pcmOut.write(chunk);
365→                buf.clear();
366→                extractor.advance();
367→            }
368→        } else {
369→            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
370→            MediaCodec codec = MediaCodec.createDecoderByType(mime);
371→            codec.configure(format, null, null, 0);
372→            codec.start();
373→
374→            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
375→            boolean inputDone = false;
376→            boolean outputDone = false;
377→
378→            while (!outputDone) {
379→                // 送入压缩数据
380→                if (!inputDone) {
381→                    int inputIdx = codec.dequeueInputBuffer(10000);
382→                    if (inputIdx >= 0) {
383→                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
384→                        int size = extractor.readSampleData(inputBuf, 0);
385→                        if (size < 0) {
386→                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
387→                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
388→                            inputDone = true;
389→                        } else {
390→                            codec.queueInputBuffer(inputIdx, 0, size,
391→                                extractor.getSampleTime(), 0);
392→                            extractor.advance();
393→                        }
394→                    }
395→                }
396→
397→                // 取出PCM数据
398→                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
399→                if (outputIdx >= 0) {
400→                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
401→                        outputDone = true;
402→                    }
403→                    if (info.size > 0) {
404→                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
405→                        byte[] chunk = new byte[info.size];
406→                        outputBuf.get(chunk);
407→                        pcmOut.write(chunk);
408→                    }
409→                    codec.releaseOutputBuffer(outputIdx, false);
410→                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
411→                    MediaFormat outFmt = codec.getOutputFormat();
412→                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
413→                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
414→                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
415→                }
416→            }
417→
418→            codec.stop();
419→            codec.release();
420→        }
421→
422→        extractor.release();
423→
424→        byte[] pcmBytes = pcmOut.toByteArray();
425→        if (pcmBytes.length < 100) {
426→            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
427→        }
428→
429→        // PCM bytes -> float samples (16-bit little-endian)
430→        int numSamples = pcmBytes.length / 2;
431→        float[] allSamples = new float[numSamples];
432→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
433→        for (int i = 0; i < numSamples; i++) {
434→            allSamples[i] = bb.getShort() / 32768.0f;
435→        }
436→
437→        // 立体声 -> 单声道
438→        float[] mono;
439→        if (channels > 1) {
440→            int monoLen = numSamples / channels;
441→            mono = new float[monoLen];
442→            for (int i = 0; i < monoLen; i++) {
443→                float sum = 0;
444→                for (int c = 0; c < channels; c++) {
445→                    sum += allSamples[i * channels + c];
446→                }
447→                mono[i] = sum / channels;
448→            }
449→        } else {
450→            mono = allSamples;
451→        }
452→
453→        // 重采样到16kHz
454→        if (sampleRate != 16000) {
455→            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
456→            mono = resample(mono, sampleRate, 16000);
457→        }
458→
459→        float durationSec = mono.length / 16000.0f;
460→        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
461→            String.format("%.1f", durationSec) + "s @ 16kHz mono");
462→
463→        if (durationSec < 0.3f) {
464→            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
465→        }
466→
467→        return mono;
468→    }
