488→    // ===== Sherpa-ONNX 离线识别（分段提升准确率） =====
489→    private String transcribeSherpa(String audioFile) throws Exception {
490→        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
491→        float[] samples = decodeAudio(audioFile);
492→
493→        AssetManager assetManager = getAssets();
494→
495→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
496→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
497→
498→        OfflineModelConfig modelConfig = new OfflineModelConfig();
499→        modelConfig.setParaformer(paraformerConfig);
500→        modelConfig.setTokens("models/paraformer/tokens.txt");
501→        modelConfig.setNumThreads(4);
502→        modelConfig.setDebug(false);
503→
504→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
505→        config.setModelConfig(modelConfig);
506→        config.setDecodingMethod("greedy_search");
507→
508→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
509→
510→        // 分段识别：每段30秒，提高长音频准确率
511→        int chunkSamples = 30 * 16000;
512→        int totalChunks = (int) Math.ceil((double) samples.length / chunkSamples);
513→        StringBuilder allText = new StringBuilder();
514→
515→        if (totalChunks <= 1) {
516→            // 短音频直接识别
517→            OfflineStream stream = recognizer.createStream();
518→            stream.acceptWaveform(samples, 16000);
519→            recognizer.decode(stream);
520→            OfflineRecognizerResult result = recognizer.getResult(stream);
521→            allText.append(result.getText() != null ? result.getText().trim() : "");
522→            stream.release();
523→        } else {
524→            // 长音频分段识别
525→            for (int ci = 0; ci < totalChunks; ci++) {
526→                int finalCi = ci;
527→                runOnUiThread(() -> tvStatus.setText(
528→                    String.format("离线识别 %d/%d...", finalCi + 1, totalChunks)));
529→
530→                int start = ci * chunkSamples;
531→                // 加1秒重叠避免截断
532→                int overlap = ci > 0 ? 16000 : 0;
533→                int actualStart = Math.max(0, start - overlap);
534→                int end = Math.min(samples.length, start + chunkSamples);
535→                int len = end - actualStart;
536→
537→                if (len < 1600) continue; // 不足0.1秒跳过
538→
539→                float[] chunk = new float[len];
540→                System.arraycopy(samples, actualStart, chunk, 0, len);
541→
542→                OfflineStream stream = recognizer.createStream();
543→                stream.acceptWaveform(chunk, 16000);
544→                recognizer.decode(stream);
545→                OfflineRecognizerResult result = recognizer.getResult(stream);
546→                String text = result.getText() != null ? result.getText().trim() : "";
547→
548→                if (!text.isEmpty()) {
549→                    // 去除重叠部分导致的重复
550→                    if (ci > 0 && allText.length() > 0 && overlap > 0) {
551→                        String prev = allText.toString();
552→                        for (int t = Math.min(5, text.length()); t > 0; t--) {
553→                            if (prev.endsWith(text.substring(0, t))) {
554→                                text = text.substring(t);
555→                                break;
556→                            }
557→                        }
558→                    }
559→                    allText.append(text);
560→                }
561→                stream.release();
562→            }
563→        }
564→
565→        recognizer.release();
566→        return allText.toString().trim();
567→    }
